async (params, browser) => {
  // Open new issue form
  await browser.open(`https://github.com/${params.repo}/issues/new`)

  // Wait for issue form
  await browser.waitForSelector('input[id=\'issue_title\'], input[name=\'issue[title]\']', 15000)

  // Let form render
  await browser.wait(2000)

  // Fill issue title
  const fill_title = await browser.evaluate(`const titleInput = document.querySelector('input[id="issue_title"], input[name="issue[title]"]'); if (!titleInput) { return { success: false, message: 'Issue title input not found - make sure you are logged in and have permission to create issues' }; } const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set; nativeInputValueSetter.call(titleInput, params.title); titleInput.dispatchEvent(new Event('input', { bubbles: true })); titleInput.dispatchEvent(new Event('change', { bubbles: true })); return { step: 'title_filled' }`)

  // Brief pause
  await browser.wait(500)

  // Fill issue body
  const fill_body = await browser.evaluate(`const bodyInput = document.querySelector('textarea[id="issue_body"], textarea[name="issue[body]"], #issue_body'); if (bodyInput) { const nativeTextAreaSetter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set; nativeTextAreaSetter.call(bodyInput, params.body); bodyInput.dispatchEvent(new Event('input', { bubbles: true })); bodyInput.dispatchEvent(new Event('change', { bubbles: true })); } return { step: 'body_filled' }`)

  // Brief pause
  await browser.wait(500)

  // Submit issue
  const submit = await browser.evaluate(`const submitBtn = document.querySelector('button[type="submit"][data-disable-with], button.btn-primary[type="submit"], button[data-testid="create-issue-button"]'); if (!submitBtn) { return { success: false, message: 'Submit button not found' }; } submitBtn.click(); return { step: 'submitted' }`)

  // Wait for issue creation
  await browser.wait(3000)

  // Verify issue created
  const result = await browser.evaluate(`const url = window.location.href; const match = url.match(/\/issues\/(\d+)/); if (match) { const titleEl = document.querySelector('.js-issue-title, [data-testid="issue-title"], h1 bdi'); return { success: true, number: parseInt(match[1], 10), title: titleEl ? titleEl.textContent.trim() : '', url: url }; } return { success: false, message: 'Issue may not have been created. Current URL: ' + url }`)

  return result
}
